-
-    fn file_exists(&self, path: &Path) -> bool {
-        path.exists()
-    }
-
-    fn file_size(&self, path: &Path) -> Result<u64, String> {
-        std::fs::metadata(path)
-            .map(|m| m.len())
-            .map_err(|e| format!("metadata {}: {e}", path.display()))
