-                        rule_id: o.workflow_id.clone(),
-                        actions: vec![prev_action.to_string(), o.action.to_string()],
-                    });
-                }
-            }
-            seen.insert(o.workflow_id.clone(), o.action);
-        }
-        Ok(())
-    }
-
-    fn check_policy_conflicts(overrides: &[PolicyOverride]) -> Result<(), OverrideError> {
