-    } else if baseline.input_hash != candidate.input_hash {
-        RootCause::InputDivergence {
-            upstream_rule_id: baseline.rule_id.clone(),
-            upstream_position: baseline.node_id,
-        }
-    } else {
-        RootCause::Unknown
-    }
-}
